    if not triples:
        return ""

    # Build entity relationship graph - map subjects to their triples
    entity_to_triples = {}
    for t in triples:
        if t.subject not in entity_to_triples:
            entity_to_triples[t.subject] = []
        entity_to_triples[t.subject].append(t)

    # Find the main subject (entity that appears most as subject)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1

    if subject_counts:
        main_subject = max(subject_counts, key=subject_counts.get)
    else:
        main_subject = triples[0].subject

    # Helper function to determine if an entity is a person
    def is_person(name):
        person_indicators = ['footballer', 'player', 'manager', 'coach', 'captain', 'president', 'chairman']
        name_lower = name.lower()
        # Check if name contains person indicators
        if any(indicator in name_lower for indicator in person_indicators):
            return True
        # Check if name appears to be a person name (capitalized, no special chars)
        if name and not name.startswith('"') and not name.startswith('('):
            # Common person name patterns
            if ' ' in name and len(name.split()) <= 3:
                parts = name.split()
                if all(part[0].isupper() for part in parts if part):
                    return True
        return False

