    main_entity = main_subject
    for entity in subject_groups:
        if any(pred in entity_groups.get(entity, []) for pred in ['league', 'manager', 'ground', 'fullName', 'season']):
            main_entity = entity
            break

    # Build sentence starting from main entity
    result_parts = []
    mentioned_entities = set()

    # First, add all triples for the main subject
    if main_entity in subject_groups:
        for t, phrase in subject_groups[main_entity]:
            result_parts.append((t, phrase, main_entity))
            mentioned_entities.add(t.object)

    # Then add related information about other entities
    for entity, triples in subject_groups.items():
        if entity == main_entity:
            continue

        for t, phrase in triples:
            # Check if this entity was mentioned in the main subject's triples
            if entity in mentioned_entities:
                # Build relative clause for this entity
                result_parts.append((t, phrase, entity))

    if not result_parts:
        return ""

    # Build the final sentence
    first_t, first_phrase, _ = result_parts[0]
    result = first_phrase
    last_subject = first_t.subject
    mentioned_entities = {first_t.subject, first_t.object}

    for i in range(1, len(result_parts)):
        t, phrase, entity = result_parts[i]

        if t.subject == last_subject:
            # Same subject - add as additional information
            if " is " in phrase:
                parts = phrase.split(" is ", 1)
                result = result + ", which is " + parts[1]
            elif " plays at " in phrase:
                parts = phrase.split(" plays at ", 1)
                result = result + ", which plays at " + parts[1]
            elif " competes in " in phrase:
                parts = phrase.split(" competes in ", 1)
                result = result + ", which competes in " + parts[1]
            else:
                result = result + ", which " + phrase
        elif t.object in mentioned_entities:
            # This triple's object was mentioned before - add as relative clause
            if is_person(t.subject):
                pronoun = "who"
            else:
                pronoun = "which"

            if " is " in phrase:
