                result = result + ", " + pronoun + " is " + parts[1]
            elif " capital is " in phrase:
                parts = phrase.split(" capital is ", 1)
                result = result + ", whose capital is " + parts[1]
            elif " led by " in phrase:
                parts = phrase.split(" led by ", 1)
                result = result + ", which is led by " + parts[1]
            else:
                result = result + ", " + pronoun + " " + phrase
        else:
            # Add with conjunction
            if i == len(result_parts) - 1:
                result = result + ", and " + phrase
            else:
                result = result + ", " + phrase

        mentioned_entities.add(t.subject)
        mentioned_entities.add(t.object)
        last_subject = t.subject

    return result + "."

